ValidationRule.errorConditionFormula:
AND(NOT($Permission.CONTAINER_Bypass_Validation_Rule),
IF(AND(OR( RecordType.Name = 'Container GENSET Quote', 
RecordType.Name = 'CONTAINER_NT_Quote'), NOT(ISPICKVAL(CONTAINER_Status__c,"Order/Pending for Job #")),
NOT(ISPICKVAL(CONTAINER_Status__c,"Job # Issued")), NOT(ISPICKVAL(CONTAINER_Status__c,"ASO Released")), NOT(ISPICKVAL(CONTAINER_Status__c,"SO Released")), NOT(ISPICKVAL(CONTAINER_Status__c,"Lost")), NOT(ISPICKVAL(CONTAINER_Status__c,"Cancelled")), NOT(ISBLANK(CONTAINER_Job__c))),true,false
)
)
